      "content": "const { randomUUID } = require('node:crypto');
const tasksService = require('../tasks/service');

let commentsStore = {};

function addComment(taskId, message) {
  if (!message) {
    return null;
  }

  const task = tasksService.getTaskById(taskId);
  if (!task) {
    return null;
  }

  const commentId = randomUUID();
  commentsStore[commentId] = { taskId, message };
  return commentsStore[commentId];
}

function getCommentsByTaskId(taskId) {
  return Object.values(commentsStore).filter(comment => comment.taskId === taskId);
}

module.exports = {
  addComment,
  getCommentsByTaskId,
};
